function extractNameFromText(...parts) {
  const text = parts.filter(Boolean).join(' | ');
  if (!text) return { first_name: '', last_name: '', full_name: '' };
  const patterns = [
    /(?:Head Coach|Assistant Coach|Associate Head Coach|Athletic Director|Program Director|Coach|Director)\s*[:\-]\s*([A-Z][a-z]+(?:\s+[A-Z][a-z'.-]+){1,2})/i,
