    /\b([A-Z][a-z]+(?:\s+[A-Z][a-z'.-]+){1,2})\b/
  ];
  let candidate = '';
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match && match[1]) {
      candidate = match[1];
      break;
    }
  }
  if (!candidate) return { first_name: '', last_name: '', full_name: '' };
  const cleaned = candidate
    .replace(/\b(head|assistant|associate|boys|girls|varsity|junior varsity|jv|coach|director|soccer|basketball|football|baseball|softball|volleyball|athletics)\b/ig, '')
    .replace(/\s+/g, ' ')
    .trim();
  const pieces = cleaned.split(/\s+/).filter(Boolean);
  if (pieces.length < 2) return { first_name: '', last_name: '', full_name: '' };
  return { first_name: pieces[0], last_name: pieces.slice(1).join(' '), full_name: pieces.join(' ') };
}

