const inputItems = $input.all();

const normalizeText = (value) => String(value || '').toLowerCase().replace(/[^a-z0-9@]+/g, ' ').replace(/\s+/g, ' ').trim();
const extractEmail = (value) => {
  const match = String(value || '').toLowerCase().match(/[a-z0-9._%+\-]+@[a-z0-9.\-]+\.[a-z]{2,}/i);
  return match ? match[0] : '';
};
const extractLikelyName = (row) => {
  const text = [row.search_result_title, row.description].filter(Boolean).join(' | ');
  const upper = text.match(/\b([A-Z]{2,}(?:\s+[A-Z][A-Z'.-]+)+)\b/);
  if (upper) return upper[1].toLowerCase();
  const titleCase = text.match(/\b([A-Z][a-z]+(?:\s+[A-Z][a-z'.-]+){1,2})\b/);
  return titleCase ? titleCase[1].toLowerCase() : '';
};
const canonicalUrl = (value) => {
  const rawUrl = String(value || '').trim();
  if (!rawUrl) return '';
  const withScheme = /^https?:\/\//i.test(rawUrl) ? rawUrl : 'https://' + rawUrl;
  try {
    const parsed = new URL(withScheme);
    parsed.hash = '';
    const host = parsed.hostname.toLowerCase().replace(/^www\./, '');
    const path = parsed.pathname.replace(/\/+$/, '') || '/';
    return 'https://' + host + path;
  } catch {
    return withScheme.toLowerCase();
  }
};

const seen = new Set();
let uniqueCount = 0;

return inputItems.map((item) => {
  const row = item.json || {};
  const domain = normalizeText(row.domain);
  const urlKey = canonicalUrl(row.canonical_url || row.website_url || row.url);
  const emailKey = extractEmail(row.description || row.search_result_title || '');
  const personKey = extractLikelyName(row);
  const titleKey = normalizeText(row.search_result_title || row.organization_name).slice(0, 80);
  const descKey = normalizeText(row.description).slice(0, 120);

  const key = emailKey
    ? ['email', domain, emailKey].join('|')
    : personKey
      ? ['person', domain, personKey, titleKey.slice(0, 40)].join('|')
      : ['url', urlKey || domain, titleKey || descKey].join('|');

  const isDuplicate = seen.has(key);
  if (!isDuplicate) {
    seen.add(key);
    uniqueCount += 1;
  }

  return {
    json: {
      ...row,
      _dedupe_batch_key: key,
      _dedupe_batch_isDuplicate: isDuplicate,
      _dedupe_batch_seen_count: seen.size,
      _dedupe_batch_unique_count: uniqueCount,
      _dedupe_batch_total_count: inputItems.length,
    }
  };
});

const originals = $('WF04v3+ Filter: Batch Dupes').all().map((item) => item.json || {});
const responses = $input.all();
const previousRunMatchByIndex = new Map();
let previousRunsError = null;

for (const item of responses) {
  const payload = item.json?.body ?? item.json ?? {};
  const isError = payload && typeof payload === 'object' && !Array.isArray(payload) && (typeof payload.code === 'string' || payload.hint !== undefined || payload.error !== undefined);
  const rows = (!isError && Array.isArray(payload)) ? payload : [];
  const existingRow = rows[0] || null;
  const paired = Array.isArray(item.pairedItem) ? item.pairedItem : (item.pairedItem != null ? [item.pairedItem] : []);
  const pairedIndexes = paired
    .map((entry) => (typeof entry?.item === 'number' ? entry.item : null))
    .filter((index) => index !== null);

  if (isError && !previousRunsError) {
    previousRunsError = String(payload.message || payload.error || payload.code || 'previous_runs_lookup_failed');
  }

  for (const index of pairedIndexes) {
    previousRunMatchByIndex.set(index, existingRow);
  }
}

return originals.map((original, index) => {
  const existingRow = previousRunMatchByIndex.get(index) || null;
  const seenBefore = Boolean(existingRow && existingRow.domain);
  return {
    json: {
      ...original,
      _dedupe_previous_existing_row: existingRow,
      _dedupe_previous_seen_before: seenBefore,
      _dedupe_previous_isDuplicate: false,
      _dedupe_previous_reason: seenBefore ? 'seen_before_but_not_blocking' : null,
      _dedupe_previous_error: previousRunsError,
    }
  };
});

